  "questions": [
    {
      "id": 1,
      "question": "What are the minimum Common Equity Tier 1 (CET1) capital requirements under Basel III, and how do they differ from the previous Basel II framework?",
      "category": "regulatory_compliance",
      "difficulty": "medium",
      "ground_truth": "Under Basel III, the minimum CET1 capital requirement is set at 4.5% of risk-weighted assets (RWA), which is significantly higher than the Basel II requirement of 2% for core Tier 1 capital. Basel III also introduced the Capital Conservation Buffer (CCB) of 2.5%, effectively raising the total CET1 requirement to 7%. Additionally, Basel III imposed stricter criteria for what qualifies as CET1, excluding certain hybrid instruments that were previously allowed under Basel II. These changes were phased in gradually between 2013 and 2019 to allow banks time to build up their capital buffers.",
      "expected_entities": ["Basel_III", "CET1", "Basel_II", "Capital_Conservation_Buffer", "RWA"],
      "expected_concepts": ["capital_adequacy", "risk_weighting", "minimum_capital_requirements", "regulatory_capital"],
      "source_references": ["Basel III Framework, Section II.A", "BCBS 189, Paragraph 50-56"],
      "requires_multi_hop": false,
      "scoring_rubric": {
        "entity_coverage": {"max_score": 1.0, "required_entities": ["Basel_III", "CET1", "RWA", "Capital_Conservation_Buffer"]},
