        "source_attribution": {"max_score": 1.0, "required_sources": ["Basel III Framework"]},
        "response_quality": {"max_score": 1.0, "criteria": "Must specify exact CET1 percentage (4.5%) and CCB (2.5%), and explain the change from Basel II"}
      }
