    {
      "id": 2,
      "question": "What are the key principles of the LGPD (Lei Geral de Protecao de Dados) regarding the processing of personal data by financial institutions in Brazil?",
      "category": "regulatory_compliance",
      "difficulty": "medium",
      "ground_truth": "The LGPD establishes ten legal bases for processing personal data, including consent, legitimate interest, and regulatory compliance. For financial institutions, key principles include purpose limitation, data minimization, transparency, and accountability. Financial institutions must appoint a Data Protection Officer (DPO), maintain records of processing activities, and implement appropriate technical and organizational security measures. The LGPD also grants data subjects rights such as access, correction, deletion, and portability of their personal data. Non-compliance can result in fines of up to 2% of revenue, capped at R$50 million per violation.",
      "expected_entities": ["LGPD", "DPO", "ANPD", "financial_institutions", "data_subjects"],
      "expected_concepts": ["purpose_limitation", "data_minimization", "consent", "legitimate_interest", "data_protection"],
      "source_references": ["LGPD, Articles 6-10", "LGPD, Article 41", "LGPD, Article 52"],
      "requires_multi_hop": false,
