    {
      "id": 3,
      "question": "How does the Countercyclical Capital Buffer (CCyB) work under Basel III, and when can national regulators activate it?",
      "category": "regulatory_compliance",
      "difficulty": "hard",
      "ground_truth": "The Countercyclical Capital Buffer (CCyB) is a macroprudential tool under Basel III that can range from 0% to 2.5% of risk-weighted assets, composed of CET1 capital. National regulators can activate the CCyB during periods of excessive aggregate credit growth that are judged to be associated with a buildup of system-wide risk. The buffer is designed to ensure that the banking sector builds up capital in good times that can be drawn down during stress periods. The credit-to-GDP gap is the primary reference indicator used by regulators to guide CCyB decisions. When activated, banks are given up to 12 months to comply with the higher requirement.",
      "expected_entities": ["CCyB", "Basel_III", "CET1", "BCBS", "national_regulators"],
      "expected_concepts": ["macroprudential_policy", "credit_cycle", "systemic_risk", "credit_to_GDP_gap", "countercyclical_policy"],
      "source_references": ["Basel III Framework, Section II.B", "BCBS Guidance on CCyB, 2010"],
      "requires_multi_hop": false,
      "scoring_rubric": {
        "entity_coverage": {"max_score": 1.0, "required_entities": ["CCyB", "Basel_III", "CET1"]},
        "concept_coverage": {"max_score": 1.0, "required_concepts": ["macroprudential_policy", "credit_cycle", "systemic_risk"]},
        "source_attribution": {"max_score": 1.0, "required_sources": ["Basel III Framework"]},
        "response_quality": {"max_score": 1.0, "criteria": "Must explain the 0-2.5% range, activation conditions, and credit-to-GDP gap indicator"}
      }
