    {
      "id": 4,
      "question": "What obligations does GDPR impose on financial institutions acting as data controllers for cross-border data transfers?",
      "category": "regulatory_compliance",
      "difficulty": "hard",
      "ground_truth": "Under GDPR, financial institutions acting as data controllers must ensure that cross-border transfers of personal data to third countries outside the EEA are carried out with adequate safeguards. These safeguards include adequacy decisions by the European Commission, Standard Contractual Clauses (SCCs), Binding Corporate Rules (BCRs), or approved codes of conduct and certification mechanisms. Following the Schrems II ruling, controllers must also conduct Transfer Impact Assessments (TIAs) to evaluate the legal framework of the recipient country. Financial institutions must document these transfers in their Record of Processing Activities (ROPA) and inform data subjects about the transfer mechanisms used.",
      "expected_entities": ["GDPR", "EEA", "European_Commission", "SCCs", "BCRs", "Schrems_II"],
      "expected_concepts": ["cross_border_transfer", "adequacy_decision", "data_controller", "transfer_impact_assessment", "data_protection"],
      "source_references": ["GDPR, Chapter V, Articles 44-49", "Schrems II Ruling, CJEU C-311/18"],
      "requires_multi_hop": false,
