    {
      "id": 5,
      "question": "What is the leverage ratio requirement under Basel III, and why was it introduced as a non-risk-based measure?",
      "category": "regulatory_compliance",
      "difficulty": "medium",
      "ground_truth": "The Basel III leverage ratio requires banks to maintain a minimum Tier 1 capital of 3% relative to the bank's total exposure measure, which includes on-balance-sheet exposures, derivative exposures, securities financing transaction exposures, and off-balance-sheet items. The leverage ratio was introduced as a simple, non-risk-based backstop to complement the risk-weighted capital requirements. It addresses the risk that banks might underestimate risk weights using internal models, effectively gaming the risk-weighted framework. For Global Systemically Important Banks (G-SIBs), an additional leverage ratio buffer of 50% of the G-SIB higher-loss-absorbency surcharge applies. The leverage ratio became a binding Pillar 1 requirement starting January 2018.",
      "expected_entities": ["Basel_III", "leverage_ratio", "Tier_1_capital", "G-SIBs", "Pillar_1"],
      "expected_concepts": ["non_risk_based_measure", "backstop_measure", "total_exposure", "model_risk", "loss_absorbency"],
      "source_references": ["Basel III Framework, Section III", "BCBS 270, Leverage Ratio Framework"],
      "requires_multi_hop": false,
