        "source_attribution": {"max_score": 1.0, "required_sources": ["Basel III Framework"]},
        "response_quality": {"max_score": 1.0, "criteria": "Must specify the 3% minimum, explain the exposure measure components, and rationale for non-risk-based approach"}
      }
