    {
      "id": 6,
      "question": "What are the requirements for Pillar 3 disclosure under the Basel III framework, and what information must banks publicly report?",
      "category": "regulatory_compliance",
      "difficulty": "medium",
      "ground_truth": "Pillar 3 of the Basel III framework requires banks to publicly disclose key information about their risk management practices, capital adequacy, and risk exposures to promote market discipline. Required disclosures include capital composition and adequacy ratios, credit risk exposures by asset class, market risk and operational risk measures, leverage ratio, liquidity coverage ratio, and remuneration policies. The BCBS introduced standardized disclosure templates (the DIS series) to improve comparability across institutions. Banks must publish these disclosures at least semi-annually, with some key metrics required quarterly. The revised Pillar 3 framework also requires disclosure of risk-weighted asset calculations and the impact of Basel III reforms.",
      "expected_entities": ["Pillar_3", "Basel_III", "BCBS", "market_discipline", "DIS_templates"],
      "expected_concepts": ["public_disclosure", "transparency", "market_discipline", "risk_reporting", "comparability"],
      "source_references": ["Basel III Framework, Pillar 3", "BCBS 309, Revised Pillar 3 Disclosure Requirements"],
      "requires_multi_hop": false,
