        "source_attribution": {"max_score": 1.0, "required_sources": ["Basel III Framework, Pillar 3"]},
        "response_quality": {"max_score": 1.0, "criteria": "Must list at least four categories of required disclosures and mention disclosure frequency"}
      }
    },
    {
      "id": 7,
      "question": "What are the GDPR principles relating to the lawfulness, fairness, and transparency of personal data processing?",
      "category": "regulatory_compliance",
      "difficulty": "simple",
      "ground_truth": "Article 5 of the GDPR establishes seven key data processing principles. Lawfulness requires that data processing has a valid legal basis from among the six listed in Article 6, such as consent, contractual necessity, or legitimate interest. Fairness means that data must be processed in a way that data subjects would reasonably expect and not in ways that produce unjustified adverse effects. Transparency requires controllers to provide clear, plain-language information about how data is collected, used, and shared through privacy notices. These three principles together form the foundation of the GDPR's data processing framework and are enforceable by Supervisory Authorities with fines of up to 4% of annual global turnover or EUR 20 million.",
      "expected_entities": ["GDPR", "Article_5", "Article_6", "Supervisory_Authority", "data_controller"],
      "expected_concepts": ["lawfulness", "fairness", "transparency", "legal_basis", "data_processing_principles"],
      "source_references": ["GDPR, Article 5(1)(a)", "GDPR, Article 6", "GDPR, Article 83"],
