        "concept_coverage": {"max_score": 1.0, "required_concepts": ["systemic_importance", "loss_absorbency", "capital_surcharge"]},
        "source_attribution": {"max_score": 1.0, "required_sources": ["BCBS 255"]},
        "response_quality": {"max_score": 1.0, "criteria": "Must specify the surcharge range (1-3.5%), the five assessment categories, and cumulative capital requirements"}
      }
    },
    {
      "id": 9,
      "question": "What are the data subject rights under the LGPD and how must financial institutions respond to such requests?",
      "category": "regulatory_compliance",
      "difficulty": "medium",
      "ground_truth": "Under Article 18 of the LGPD, data subjects have nine fundamental rights including confirmation of data processing, access to their data, correction of inaccurate data, anonymization or deletion of unnecessary data, data portability, information about shared data with third parties, information about consent denial consequences, and revocation of consent. Financial institutions must respond to these requests within 15 days and must provide clear, adequate, and accessible communication. The Data Protection Officer (DPO) is responsible for receiving and processing these requests. Financial institutions must maintain internal procedures for handling data subject requests and must ensure their response mechanisms are documented and auditable by the ANPD (Autoridade Nacional de Protecao de Dados).",
      "expected_entities": ["LGPD", "Article_18", "DPO", "ANPD", "data_subjects"],
      "expected_concepts": ["data_subject_rights", "right_of_access", "right_to_deletion", "data_portability", "consent_revocation"],
      "source_references": ["LGPD, Article 18", "LGPD, Article 19", "LGPD, Article 41"],
      "requires_multi_hop": false,
      "scoring_rubric": {
        "entity_coverage": {"max_score": 1.0, "required_entities": ["LGPD", "Article_18", "DPO", "ANPD"]},
        "concept_coverage": {"max_score": 1.0, "required_concepts": ["data_subject_rights", "right_of_access", "data_portability"]},
        "source_attribution": {"max_score": 1.0, "required_sources": ["LGPD, Article 18"]},
        "response_quality": {"max_score": 1.0, "criteria": "Must list at least five specific data subject rights and mention the 15-day response period"}
      }
