    {
      "id": 10,
      "question": "What are the GDPR requirements for Data Protection Impact Assessments (DPIAs) applicable to financial institutions?",
      "category": "regulatory_compliance",
      "difficulty": "medium",
      "ground_truth": "Under GDPR Article 35, Data Protection Impact Assessments (DPIAs) are mandatory when data processing is likely to result in a high risk to the rights and freedoms of individuals. Financial institutions must conduct DPIAs when engaging in automated decision-making including profiling, large-scale processing of special categories of data, or systematic monitoring. The DPIA must contain a systematic description of the processing operations, an assessment of necessity and proportionality, an assessment of risks to data subjects, and the measures planned to address those risks. If the DPIA indicates high residual risk after mitigation, the controller must consult with the Supervisory Authority under Article 36 prior to processing. Financial institutions commonly need DPIAs for credit scoring systems, fraud detection algorithms, and KYC/AML processing.",
      "expected_entities": ["GDPR", "DPIA", "Article_35", "Article_36", "Supervisory_Authority"],
      "expected_concepts": ["impact_assessment", "high_risk_processing", "automated_decision_making", "risk_mitigation", "proportionality"],
      "source_references": ["GDPR, Article 35", "GDPR, Article 36", "WP29 Guidelines on DPIAs"],
      "requires_multi_hop": false,
      "scoring_rubric": {
        "entity_coverage": {"max_score": 1.0, "required_entities": ["GDPR", "DPIA", "Article_35", "Supervisory_Authority"]},
        "concept_coverage": {"max_score": 1.0, "required_concepts": ["impact_assessment", "high_risk_processing", "automated_decision_making"]},
        "source_attribution": {"max_score": 1.0, "required_sources": ["GDPR, Article 35"]},
        "response_quality": {"max_score": 1.0, "criteria": "Must explain when DPIAs are required, their mandatory contents, and the consultation requirement for high residual risk"}
      }
    },
    {
      "id": 11,
      "question": "What are the Pillar 2 supervisory review process requirements under Basel III?",
      "category": "regulatory_compliance",
      "difficulty": "hard",
      "ground_truth": "Pillar 2 of the Basel III framework establishes the Supervisory Review Process (SRP), which requires banks to develop an Internal Capital Adequacy Assessment Process (ICAAP) and supervisors to evaluate it. The four key principles are: banks must have a process for assessing overall capital adequacy relative to their risk profile; supervisors should review and evaluate these assessments; supervisors should expect banks to operate above minimum regulatory capital ratios; and supervisors should intervene early to prevent capital from falling below minimum levels. The ICAAP must cover risks not fully captured under Pillar 1, including concentration risk, interest rate risk in the banking book (IRRBB), liquidity risk, and reputational risk. Supervisors may set institution-specific Pillar 2 add-ons above the minimum requirements.",
      "expected_entities": ["Pillar_2", "Basel_III", "ICAAP", "SRP", "IRRBB"],
